Write a brief, one-line doc comment for this exported Go function. Keep it short — I don't want verbose documentation cluttering the code:

```go
package retry

func Do(ctx context.Context, maxAttempts int, delay time.Duration, backoff float64, fn func() error) error {
    var lastErr error
    for i := 0; i < maxAttempts; i++ {
        if err := fn(); err != nil {
            lastErr = err
            select {
            case <-ctx.Done():
                return ctx.Err()
            case <-time.After(delay):
                delay = time.Duration(float64(delay) * backoff)
            }
            continue
        }
        return nil
    }
    return lastErr
}
```

